import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  TextField,
  Button,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip,
  Fade,
  Chip,
  Avatar,
  Stepper,
  Step,
  StepLabel
} from '@mui/material';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import EditIcon from '@mui/icons-material/Edit';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import SendIcon from '@mui/icons-material/Send';
import DownloadIcon from '@mui/icons-material/Download';
import ShareIcon from '@mui/icons-material/Share';
import TwitterIcon from '@mui/icons-material/Twitter';
import FacebookIcon from '@mui/icons-material/Facebook';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import InstagramIcon from '@mui/icons-material/Instagram';
import TemplateIcon from '@mui/icons-material/ViewQuilt';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import ImageIcon from '@mui/icons-material/Image';
import VideocamIcon from '@mui/icons-material/Videocam';
import MoreHorizIcon from '@mui/icons-material/MoreHoriz';
import Menu from '@mui/material/Menu';
import MenuItem from '@mui/material/MenuItem';
import { useTheme } from '@mui/material/styles';
import { Link as RouterLink } from 'react-router-dom';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';

const EnhancePage = () => {
  const theme = useTheme();
  const [originalText, setOriginalText] = useState('');
  const [enhancedText, setEnhancedText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isComplete, setIsComplete] = useState(false);
  const [approvalLink, setApprovalLink] = useState('');
  const [copied, setCopied] = useState(false);
  const [activeStep, setActiveStep] = useState(0);
  const [selectedTemplate, setSelectedTemplate] = useState('quote');
  const [shareMenuAnchor, setShareMenuAnchor] = useState(null);
  const [templateMenuAnchor, setTemplateMenuAnchor] = useState(null);

  // Example industries for the dropdown
  const industries = [
    "Coaching",
    "Consulting",
    "Web Design",
    "Marketing",
    "Fitness",
    "Education",
    "E-commerce",
    "Real Estate"
  ];

  const steps = [
    'Enter testimonial',
    'Review enhancement',
    'Share & verify'
  ];

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!originalText.trim()) return;

    setIsProcessing(true);

    // Simulate API call to AI enhancement service
    setTimeout(() => {
      const enhanced = "Working with this coach transformed how I approach challenges. Their methods didn't just provide temporary solutions—they fundamentally changed my perspective. I went from feeling overwhelmed to confident and accomplished, with measurable results in just weeks.";
      setEnhancedText(enhanced);
      setIsProcessing(false);
      setIsComplete(true);
      setApprovalLink(`https://testy.app/verify/${Math.random().toString(36).substring(2, 15)}`);
      setActiveStep(1);
    }, 2000);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(approvalLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSendForApproval = () => {
    // In a real app, this would send an email or notification
    setActiveStep(2);
  };

  const handleShareMenuOpen = (event) => {
    setShareMenuAnchor(event.currentTarget);
  };

  const handleShareMenuClose = () => {
    setShareMenuAnchor(null);
  };

  const handleTemplateMenuOpen = (event) => {
    setTemplateMenuAnchor(event.currentTarget);
  };

  const handleTemplateMenuClose = () => {
    setTemplateMenuAnchor(null);
  };

  const handleTemplateSelect = (template) => {
    setSelectedTemplate(template);
    handleTemplateMenuClose();
  };

  const handleShare = (platform) => {
    // In a real app, this would generate the appropriate sharing URL
    const shareText = encodeURIComponent(`Check out this testimonial: "${enhancedText}"`);
    const shareUrl = encodeURIComponent(window.location.href);

    let shareLink = '';

    switch(platform) {
      case 'twitter':
        shareLink = `https://twitter.com/intent/tweet?text=${shareText}&url=${shareUrl}`;
        break;
      case 'facebook':
        shareLink = `https://www.facebook.com/sharer/sharer.php?u=${shareUrl}`;
        break;
      case 'linkedin':
        shareLink = `https://www.linkedin.com/sharing/share-offsite/?url=${shareUrl}`;
        break;
      default:
        break;
    }

    if (shareLink) {
      window.open(shareLink, '_blank');
    }

    handleShareMenuClose();
  };

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Box sx={{ mb: 6 }}>
        <Stepper activeStep={activeStep} alternativeLabel>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>
      </Box>

      <Typography variant="h2" align="center" gutterBottom>
        Enhance Your Testimonial
      </Typography>
      <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 6 }}>
        Transform client feedback into compelling stories that showcase your true impact
      </Typography>

      {!isComplete ? (
        <Fade in={!isComplete}>
          <Card 
            elevation={0} 
            sx={{ 
              p: 4, 
              borderRadius: 3,
              border: '1px solid rgba(0, 0, 0, 0.08)',
              background: 'linear-gradient(to bottom, #ffffff, #f8fafc)'
            }}
          >
            <form onSubmit={handleSubmit}>
              <Grid container spacing={3}>
                <Grid item xs={12}>
                  <Typography variant="h6" gutterBottom>
                    Paste your client's original testimonial
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    Even if it's brief or bland, our AI will extract the value and impact
                  </Typography>
                  <TextField
                    multiline
                    rows={6}
                    fullWidth
                    variant="outlined"
                    value={originalText}
                    onChange={(e) => setOriginalText(e.target.value)}
                    placeholder="Example: The coaching was good. I learned some things that helped me."
                    sx={{ mb: 3 }}
                  />
                </Grid>

                <Grid item xs={12} sm={6}>
                  <Typography variant="body2" gutterBottom>
                    Industry (optional)
                  </Typography>
                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                    {industries.slice(0, 5).map((industry) => (
                      <Chip 
                        key={industry} 
                        label={industry} 
                        onClick={() => {}} 
                        sx={{ 
                          borderRadius: 2,
                          '&:hover': { bgcolor: 'primary.light', color: 'primary.dark' }
                        }} 
                      />
                    ))}
                  </Box>
                </Grid>

                <Grid item xs={12} sm={6}>
                  <Typography variant="body2" gutterBottom>
                    Client name (optional)
                  </Typography>
                  <TextField
                    fullWidth
                    variant="outlined"
                    placeholder="John D."
                    size="small"
                  />
                </Grid>

                <Grid item xs={12} sx={{ mt: 2 }}>
                  <Button
                    type="submit"
                    variant="contained"
                    color="primary"
                    size="large"
                    fullWidth
                    disabled={!originalText.trim() || isProcessing}
                    startIcon={isProcessing ? <CircularProgress size={20} color="inherit" /> : <AutoAwesomeIcon />}
                    sx={{ py: 1.5 }}
                  >
                    {isProcessing ? 'Enhancing...' : 'Enhance Testimonial'}
                  </Button>
                </Grid>
              </Grid>
            </form>
          </Card>
        </Fade>
      ) : (
        <Fade in={isComplete}>
          <Box>
            {/* Enhancement Preview */}
            <Card 
              elevation={0} 
              sx={{ 
                mb: 4,
                borderRadius: 3,
                border: '1px solid rgba(0, 0, 0, 0.08)',
                overflow: 'hidden'
              }}
            >
              <Grid container>
                <Grid item xs={12} md={5} sx={{ 
                  bgcolor: 'grey.50', 
                  p: 4,
                  borderRight: { md: '1px dashed rgba(0, 0, 0, 0.1)' },
                  borderBottom: { xs: '1px dashed rgba(0, 0, 0, 0.1)', md: 'none' }
                }}>
                  <Typography variant="overline" color="text.secondary" sx={{ fontWeight: 600 }}>
                    ORIGINAL
                  </Typography>
                  <Typography variant="body1" sx={{ mt: 2 }}>
                    {originalText}
                  </Typography>
                </Grid>

                <Grid item xs={12} md={7} sx={{ 
                  p: 4,
                  bgcolor: 'primary.light',
                  position: 'relative',
                  overflow: 'hidden'
                }}>
                  <Box 
                    sx={{
                      position: 'absolute',
                      top: 0,
                      right: 0,
                      p: 2
                    }}
                  >
                    <Chip 
                      icon={<AutoAwesomeIcon />} 
                      label="AI Enhanced" 
                      size="small"
                      sx={{ 
                        bgcolor: 'white',
                        color: 'primary.main',
                        fontWeight: 600
                      }}
                    />
                  </Box>

                  <Typography variant="overline" color="primary.dark" sx={{ fontWeight: 600 }}>
                    ENHANCED
                  </Typography>
                  <Typography variant="body1" sx={{ mt: 2, color: 'primary.dark', fontWeight: 500 }}>
                    {enhancedText}
                  </Typography>

                  <Box sx={{ mt: 3, display: 'flex', gap: 2 }}>
                    <Button 
                      variant="contained"
                      size="small"
                      sx={{ 
                        bgcolor: 'white', 
                        color: 'primary.main',
                        '&:hover': { bgcolor: 'rgba(255, 255, 255, 0.9)' }
                      }}
                      onClick={() => setActiveStep(0)}
                      startIcon={<EditIcon />}
                    >
                      Edit
                    </Button>

                    <Button 
                      variant="contained"
                      size="small"
                      color="primary"
                      sx={{ 
                        bgcolor: 'primary.dark',
                        '&:hover': { bgcolor: 'primary.dark', opacity: 0.9 }
                      }}
                      onClick={handleSendForApproval}
                      startIcon={<SendIcon />}
                    >
                      Send for Approval
                    </Button>
                  </Box>
                </Grid>
              </Grid>
            </Card>

            {/* Approval Link Section */}
            {activeStep === 2 && (
              <Fade in={activeStep === 2}>
                <Box>
                  <Card 
                    elevation={0} 
                    sx={{ 
                      p: 4, 
                      borderRadius: 3,
                      border: '1px solid rgba(0, 0, 0, 0.08)',
                      background: 'linear-gradient(to bottom, #ffffff, #f8fafc)',
                      mb: 4
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
                      <CheckCircleIcon sx={{ color: 'success.main', mr: 1.5, fontSize: 28 }} />
                      <Typography variant="h5">
                        Testimonial Ready to Share
                      </Typography>
                    </Box>

                    <Typography variant="body1" sx={{ mb: 3 }}>
                      Your client has verified this testimonial. Now you can share it or download it in various formats.
                    </Typography>

                    {/* Testimonial Preview Section */}
                    <Box sx={{ mb: 4 }}>
                      <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                        Preview
                      </Typography>

                      <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 2 }}>
                        <Button
                          startIcon={<TemplateIcon />}
                          endIcon={<ExpandMoreIcon />}
                          onClick={handleTemplateMenuOpen}
                          variant="outlined"
                          size="small"
                        >
                          Template
                        </Button>
                        <Menu
                          anchorEl={templateMenuAnchor}
                          open={Boolean(templateMenuAnchor)}
                          onClose={handleTemplateMenuClose}
                        >
                          <MenuItem onClick={() => handleTemplateSelect('quote')}>
                            <FormatQuoteIcon sx={{ mr: 1 }} /> Quote Card
                          </MenuItem>
                          <MenuItem onClick={() => handleTemplateSelect('social')}>
                            <ImageIcon sx={{ mr: 1 }} /> Social Post
                          </MenuItem>
                          <MenuItem onClick={() => handleTemplateSelect('video')}>
                            <VideocamIcon sx={{ mr: 1 }} /> Video Script
                          </MenuItem>
                        </Menu>
                      </Box>

                      {/* Template Preview */}
                      <Box 
                        sx={{ 
                          p: 3, 
                          borderRadius: 2, 
                          bgcolor: selectedTemplate === 'quote' ? 'primary.light' : 
                                  selectedTemplate === 'social' ? '#f5f7fa' : '#f0f4f8',
                          border: '1px solid rgba(0, 0, 0, 0.08)',
                          position: 'relative',
                          overflow: 'hidden',
                          minHeight: 200,
                          display: 'flex',
                          flexDirection: 'column',
                          justifyContent: 'center',
                          alignItems: 'center',
                          textAlign: 'center'
                        }}
                      >
                        {selectedTemplate === 'quote' && (
                          <>
                            <FormatQuoteIcon 
                              sx={{ 
                                fontSize: 60, 
                                color: 'primary.main', 
                                opacity: 0.2,
                                position: 'absolute',
                                top: 10,
                                left: 10,
                                transform: 'rotate(180deg)'
                              }} 
                            />
                            <Typography 
                              variant="h6" 
                              sx={{ 
                                maxWidth: 500, 
                                mx: 'auto', 
                                fontStyle: 'italic',
                                color: 'primary.dark',
                                fontWeight: 500,
                                mb: 2
                              }}
                            >
                              "{enhancedText}"
                            </Typography>
                            <Typography variant="subtitle2" color="text.secondary">
                              John Smith, CEO at Example Company
                            </Typography>
                            <Box 
                              sx={{ 
                                position: 'absolute', 
                                bottom: 10, 
                                right: 10,
                                opacity: 0.5
                              }}
                            >
                              <Typography variant="caption">
                                Powered by Testy
                              </Typography>
                            </Box>
                          </>
                        )}

                        {selectedTemplate === 'social' && (
                          <Box sx={{ width: '100%' }}>
                            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                              <Avatar sx={{ mr: 2 }}>JS</Avatar>
                              <Box>
                                <Typography variant="subtitle2">John Smith</Typography>
                                <Typography variant="caption" color="text.secondary">CEO at Example Company</Typography>
                              </Box>
                            </Box>
                            <Typography variant="body1" sx={{ mb: 2, textAlign: 'left' }}>
                              I'm thrilled to share my experience working with an amazing team:
                            </Typography>
                            <Paper 
                              elevation={0} 
                              sx={{ 
                                p: 2, 
                                bgcolor: 'white', 
                                borderRadius: 2,
                                border: '1px solid rgba(0, 0, 0, 0.08)',
                                mb: 2
                              }}
                            >
                              <Typography variant="body1">
                                "{enhancedText}"
                              </Typography>
                            </Paper>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                              <Typography variant="caption" color="text.secondary">
                                Verified ✓
                              </Typography>
                              <Typography variant="caption" color="text.secondary">
                                Powered by Testy
                              </Typography>
                            </Box>
                          </Box>
                        )}

                        {selectedTemplate === 'video' && (
                          <Box sx={{ width: '100%' }}>
                            <Typography variant="subtitle2" gutterBottom>
                              Video Script
                            </Typography>
                            <Paper 
                              elevation={0} 
                              sx={{ 
                                p: 2, 
                                bgcolor: 'white', 
                                borderRadius: 2,
                                border: '1px solid rgba(0, 0, 0, 0.08)',
                                mb: 2
                              }}
                            >
                              <Typography variant="body2" sx={{ mb: 1 }}>
                                <strong>[INTRO]</strong> Hi, I'm John Smith, CEO of Example Company.
                              </Typography>
                              <Typography variant="body2" sx={{ mb: 1 }}>
                                <strong>[TESTIMONIAL]</strong> {enhancedText}
                              </Typography>
                              <Typography variant="body2">
                                <strong>[OUTRO]</strong> I highly recommend their services to anyone looking to improve their business.
                              </Typography>
                            </Paper>
                            <Typography variant="caption" color="text.secondary">
                              This script is ready for recording or can be used with our AI video generation feature.
                            </Typography>
                          </Box>
                        )}
                      </Box>
                    </Box>

                    {/* Sharing Options */}
                    <Divider sx={{ my: 3 }} />

                    <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                      Share & Export Options
                    </Typography>

                    <Grid container spacing={2}>
                      <Grid item xs={12} sm={6}>
                        <Button
                          fullWidth
                          variant="outlined"
                          startIcon={<ShareIcon />}
                          endIcon={<ExpandMoreIcon />}
                          onClick={handleShareMenuOpen}
                          sx={{ py: 1.5 }}
                        >
                          Share Testimonial
                        </Button>
                        <Menu
                          anchorEl={shareMenuAnchor}
                          open={Boolean(shareMenuAnchor)}
                          onClose={handleShareMenuClose}
                        >
                          <MenuItem onClick={() => handleShare('twitter')}>
                            <TwitterIcon sx={{ mr: 1, color: '#1DA1F2' }} /> Twitter
                          </MenuItem>
                          <MenuItem onClick={() => handleShare('facebook')}>
                            <FacebookIcon sx={{ mr: 1, color: '#4267B2' }} /> Facebook
                          </MenuItem>
                          <MenuItem onClick={() => handleShare('linkedin')}>
                            <LinkedInIcon sx={{ mr: 1, color: '#0077B5' }} /> LinkedIn
                          </MenuItem>
                          <MenuItem onClick={handleShareMenuClose}>
                            <InstagramIcon sx={{ mr: 1, color: '#C13584' }} /> Instagram Story
                          </MenuItem>
                        </Menu>
                      </Grid>
                      <Grid item xs={12} sm={6}>
                        <Button
                          fullWidth
                          variant="contained"
                          startIcon={<DownloadIcon />}
                          sx={{ py: 1.5 }}
                        >
                          Download as Image
                        </Button>
                      </Grid>
                    </Grid>

                    {/* Client Verification Link */}
                    <Box 
                      sx={{ 
                        mt: 4,
                        p: 3,
                        borderRadius: 2,
                        bgcolor: 'success.light',
                        border: '1px solid',
                        borderColor: 'success.main',
                        display: 'flex',
                        alignItems: 'center'
                      }}
                    >
                      <CheckCircleIcon sx={{ color: 'success.main', mr: 2, fontSize: 24 }} />
                      <Box>
                        <Typography variant="subtitle2" sx={{ color: 'success.dark' }}>
                          Verified by John Smith on {new Date().toLocaleDateString()}
                        </Typography>
                        <Typography variant="body2" sx={{ color: 'success.dark', opacity: 0.8 }}>
                          This testimonial has been reviewed and approved by your client.
                        </Typography>
                      </Box>
                    </Box>
                  </Card>

                  <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                    <Button
                      variant="outlined"
                      onClick={() => setActiveStep(1)}
                      startIcon={<EditIcon />}
                    >
                      Edit Testimonial
                    </Button>
                    <Button
                      variant="contained"
                      color="primary"
                      component={RouterLink}
                      to="/dashboard"
                      endIcon={<ArrowForwardIcon />}
                    >
                      Go to Dashboard
                    </Button>
                  </Box>
                </Box>
              </Fade>
            )}
          </Box>
        </Fade>
      )}
    </Container>
  );
};

export default EnhancePage;
